#include <iostream>
#include <vector>
#include <algorithm>

// 冒泡排序函数:对vector进行升序排序
void bubbleSort(std::vector<int>& nums)
{
    int n = nums.size();
    // 外层循环控制需要进行多少轮比较
    for (int i = 0; i < n - 1; i++)
    {
        // 内层循环进行每一轮的相邻元素比较和交换
        // 每完成一轮，最大的元素会"浮"到数组末尾，因此可以减少一次比较
        for (int j = 0; j < n - i - 1; j++)
        {
            if (nums[j] > nums[j + 1])
            {
                std::swap(nums[j], nums[j + 1]);
            }
        }
    }
}

// 打印vector元素的辅助函数
void printVector(const std::vector<int>& nums)
{
    for (int num : nums)
    {
        std::cout << num << " ";
    }
    std::cout << std::endl;
}

int main()
{
    // 测试案例1:基本排序
    std::vector<int> test1 = { 3, 1, 4, 1, 5 };
    std::vector<int> expected1 = { 1, 1, 3, 4, 5 };
    bubbleSort(test1);
    std::cout << "案例1排序结果: ";
    printVector(test1);
    std::cout << "是否正确: " << std::boolalpha << (test1 == expected1) << std::endl << std::endl;

    return 0;
}

