#include <iostream>
#include <thread>
#include <vector>
#include <chrono>
#include <numeric>
#include <algorithm>
#include <cstdint>

// 线程函数：处理数据的一部分（核心逻辑不变，优化参数类型）
void processSegment(std::vector<int>& data, size_t start, size_t end, int multiplier) 
{
    // 改用 size_t:避免 int 溢出（处理超大数据集时更安全）
    for (size_t i = start; i < end; ++i)
    {
        data[i] *= multiplier;
    }
}

// 创建线程并分配任务（优化边界处理和安全检查）
void processLargeData(std::vector<int>& data, int threadNum, int multiplier) {
    // 1. 处理空数据集：直接返回，避免后续无效计算
    if (data.empty()) 
    {
        return;
    }

    // 2. 修正线程数:确保在合理范围(1 ~ 数据量)
    size_t dataSize = data.size();
    size_t validThreadNum = static_cast<size_t>(threadNum);
    validThreadNum = std::max(static_cast<size_t>(1), std::min(validThreadNum, dataSize));
    size_t segmentSize = dataSize / validThreadNum;
    size_t remaining = dataSize % validThreadNum; // 剩余数据量（分配给最后一个线程）

    // 3. 创建线程：增加异常捕获，避免线程创建失败导致崩溃
    std::vector<std::thread> threads;
    try 
    {
        size_t currentStart = 0;
        for (size_t i = 0; i < validThreadNum; ++i) 
        {   // 改用 size_t:与数据量类型匹配
            size_t currentEnd = currentStart + segmentSize;
            // 最后一个线程承担剩余数据(i == validThreadNum - 1 时补充 remaining)
            if (i == validThreadNum - 1)
            {
                currentEnd += remaining;
            }
            threads.emplace_back(processSegment, std::ref(data), currentStart, currentEnd, multiplier);
            currentStart = currentEnd;
            // emplace_back 可能抛出异常（如系统资源不足），用 try-catch 捕获
        }
    }
    catch (const std::system_error& e) 
    {
        // 线程创建失败：输出错误信息，并等待已创建的线程完成
        std::cerr << "线程创建失败：" << e.what() << std::endl;
        for (auto& t : threads)
        {
            if (t.joinable())
            {
                t.join();
            }
        }
        return;
    }

    // 4. 等待所有已创建的线程完成（无论是否有创建失败，确保不泄漏线程）
    for (auto& t : threads)
    {
        if (t.joinable())
        {
            t.join();
        }
    }
}

// 生成测试用例数据（逻辑不变，优化参数说明）
std::vector<int> generateTestData(size_t size, int start = 1) 
{   
    // 改用 size_t:明确“数量”的无符号属性
    std::vector<int> data(size);
    // 生成 [start, start+1, ..., start+size-1] 的连续整数
    std::iota(data.begin(), data.end(), start);
    return data;
}

// 计算预期结果（逻辑不变）
std::vector<int> getExpectedResult(const std::vector<int>& original, int multiplier) 
{
    std::vector<int> expected = original;
    for (auto& val : expected)
    {
        val *= multiplier;
    }
    return expected;
}

// 检查结果是否正确（逻辑不变，优化参数类型）
bool checkResult(const std::vector<int>& result, const std::vector<int>& expected) 
{
    // 用 std::equal 逐元素对比，确保结果一致
    return result.size() == expected.size() && std::equal(result.begin(), result.end(), expected.begin());
}

// 打印向量内容（优化输出格式，增加空向量判断）
void printVector(const std::vector<int>& v, size_t maxElements = 10) 
{
    if (v.empty()) 
    {  // 空向量单独处理，避免输出 "[, ...]" 等异常格式
        std::cout << "[]";
        return;
    }

    std::cout << "[";
    size_t count = 0;
    for (const auto& val : v) {
        if (count >= maxElements) {
            std::cout << ", ...";
            break;
        }
        if (count > 0) {
            std::cout << ", ";
        }
        std::cout << val;
        ++count;
    }
    std::cout << "]";
}

