        std::vector<int> original = data;
        int threads = 2;
        int multiplier = 2;

        processLargeData(data, threads, multiplier);
        std::vector<int> expected = getExpectedResult(original, multiplier);

        std::cout << "案例1: 小数据集,2线程,乘以2" << std::endl;
        std::cout << "原始数据: "; printVector(original); std::cout << std::endl;
        std::cout << "处理结果: "; printVector(data); std::cout << std::endl;
        std::cout << "预期结果: "; printVector(expected); std::cout << std::endl;
        std::cout << "结果正确: " << std::boolalpha << checkResult(data, expected) << std::endl << std::endl;
    }

    return 0;
}

