using namespace std;

// 打印向量内容的辅助函数
void printVector(const vector<int>& vec) {
    cout << "[";
    for (size_t i = 0; i < vec.size(); ++i) {
        cout << vec[i];
        if (i != vec.size() - 1) {
            cout << ", ";
        }
    }
    cout << "]";
}

// 移除向量中的重复元素（去重后保持排序状态）
vector<int> removeDuplicates(vector<int>& data) {
    // 处理空向量情况
    if (data.empty()) {
        return {};
    }

    // 排序使相同元素相邻
    sort(data.begin(), data.end());

    // 去重逻辑：保留第一个出现的元素和与前一个不同的元素
    vector<int> result;
    result.push_back(data[0]);
    for (size_t i = 1; i < data.size(); ++i) {
        if (data[i] != data[i - 1]) {
            result.push_back(data[i]);
        }
    }

    return result;
}

