#define _CRT_SECURE_NO_WARNINGS 1
#include <iostream>
#include <cstring>
using namespace std;

void reverseString(char* str)
{
    // 防御性判断:检查输入指针是否为NULL
    if (str == nullptr) {
        return;
    }

    // 计算字符串长度
    int length = strlen(str);

    // 处理空字符串或单字符字符串的情况（无需反转）
    if (length <= 1) {
        return;
    }

    // 双指针初始化：左指针指向字符串开头，右指针指向最后一个有效字符
    char* left = str;
    char* right = str + length - 1;

    // 双指针交换法反转字符串
    while (left < right) {
        // 交换两个指针指向的字符
        char temp = *left;
        *left = *right;
        *right = temp;

        // 移动指针
        left++;
        right--;
    }
}


