struct WordVec 
{
    const char* word;  
    float* vec;        
    int dim;           
};


float cosSim(float* vec1, float* vec2, int dim) 
{
    // 计算两个词向量的余弦相似度（NLP论文中衡量词相关性的核心算法）
    // 原理：通过向量夹角余弦值判断相似度，范围[-1,1]，值越接近1表示语义越相似
    // 校验函数：对比实际相似度与预期范围，返回是否符合预期
    //不要改变主函数格式
}

int main() {
    // -------------------------- 案例1：水果类单词（高相似度，3维） --------------------------
    float vecApple[] = { 0.28, 0.56, 0.12 };
    float vecBanana[] = { 0.32, 0.51, 0.15 };
    WordVec case1[] = { {"apple", vecApple, 3}, {"banana", vecBanana, 3} };
    float sim1 = cosSim(case1[0].vec, case1[1].vec, case1[0].dim);
    checkSimilarity(sim1, 0.9, 1.0, "案例1：apple vs banana（水果类）");

    return 0;
}

