using namespace std;

struct UserBehavior 
{
    const char* userID;   
    const char* itemID;   
    int buyCount;         
};

// 函数指针：定义数据筛选规则
typedef bool (*FilterFunc)(const UserBehavior*);

// 筛选规则1：购买次数≥2的记录
// 筛选规则2：指定用户（user101）的记录
// 筛选规则3：指定商品（item201）的记录
// 筛选规则4：购买次数=1的记录
// 筛选规则5：指定用户（user102）且购买次数≥1的记录
// 筛选规则6：购买次数>3的记录
// 筛选规则7：指定商品（item204）的记录
// 筛选规则8：用户ID包含"user10"的记录（简化判断：前5字符为"user1"）
// 筛选规则9：商品ID包含"item20"的记录（前6字符为"item20"）
// 筛选规则10：购买次数≤2的记录
// 筛选规则11：指定用户（user103）的记录（原案例11，移到main外）
// 筛选规则12：指定商品（item202）的记录（原案例12，移到main外）
// 筛选规则13：购买次数=0的记录（原案例13，移到main外）
// 筛选规则14：指定用户（user104）且购买次数>4的记录（原案例14，移到main外）
// 筛选规则15：指定商品（item203）的记录（原案例15，移到main外）
// 筛选规则16：购买次数=5的记录（原案例16，移到main外）
// 筛选规则17：指定用户（user106）的记录（原案例17，移到main外）
// 筛选规则18：指定商品（item207）的记录（原案例18，移到main外）
// 筛选规则19：购买次数≥3且≤5的记录（原案例19，移到main外）
// 筛选规则20：指定用户（user111）的记录（原案例20，移到main外）
// 按规则筛选数据并统计数量（核心工具函数，逻辑无问题）

int countFiltered(UserBehavior* dataset, int size, FilterFunc filter) 
{
    int count = 0;
    UserBehavior* dataPtr = dataset;
    for (int i = 0; i < size; i++) {
        if (filter(dataPtr)) { // 调用函数指针指定的筛选规则
            count++;
        }
        dataPtr++;
    }
    return count;
}

