    int case1Count = countFiltered(behaviorDataset, dataSize, filterHighBuy);
    cout << "案例1：购买次数≥2的记录数: " << case1Count << " ";
    bool case1Correct = (case1Count == 14);
    cout << "案例1校验: " << (case1Correct ? "true" : "false") << "  ";

    return 0;
}

