// 查找频谱中的峰值频率（故障诊断中识别异常频率常用）
// 释放频谱数据内存的工具函数（避免 20 个案例重复写 free）

int main () 
 {
 srand ((unsigned int) time (nullptr));

 // ===================== 案例 1：200Hz 峰值（基础故障频率） =====================
 const int CASE1_POINTS = 100;
 SpectrumData case1Spec;
 case1Spec.freqPointNum = CASE1_POINTS;
 case1Spec.freq = (float*) malloc (CASE1_POINTS * sizeof (float));
 case1Spec.amplitude = (float*) malloc (CASE1_POINTS * sizeof (float));
 // 生成数据：频率 0-990Hz（步长 10），200Hz 处振幅 0.8g（峰值）
 for (int i = 0; i < CASE1_POINTS; i++) {
 case1Spec.freq [i] = i * 10;
 case1Spec.amplitude [i] = (case1Spec.freq [i] == 200) ? 0.8f : (0.1f + (rand () % 20) / 100.0f);
 }
 float case1Peak = findPeakFreq (case1Spec);
