using namespace std;

// 补充核心函数声明（原代码调用未声明，避免编译错误）
void calibratePH(float* phArr, int len, float offset);

// 核心功能：pH校正函数 calibratePH功能：给传入的pH数据数组中所有元素加指定偏移量，用于修正传感器的系统误差（如传感器长期使用后存在固定偏差）
//指针操作核心：1. 定义指针 ptr 初始指向数组首元素 phArr（数组名本质是指向首元素的指针）；2. 循环中通过 * ptr += offset 解引用指针，直接修改当前指向的pH值（等价于 phArr[i] += offset）；3. 每次循环后 ptr++ 使指针向后移动1位，指向数组的下一个元素，直到遍历完所有数据
//测试案例结构体 PHTestCase作用：将每个测试案例的“原始pH数据、校正偏移量、预期结果、案例编号”封装成一个结构体，便于管理20个案例，避免代码冗余。
//PHTestCase成员说明：raw[5]：存储5个原始pH数据（模拟1个监测点的5次采样值）；offset：当前案例的校正偏移量（可正可负，覆盖不同校正场景）；expected[5]：预先计算的校正后预期结果（用于后续校验）；caseID：案例编号（如 Case01），用于输出时区分不同案例

// 实现核心校正函数（原代码只描述未定义）
void calibratePH(float* phArr, int len, float offset) {
    float* ptr = phArr; // 指针指向数组首元素
    for (int i = 0; i < len; i++) {
        *ptr += offset;   // 解引用指针修改当前元素值
        ptr++;            // 指针后移指向 next 元素
    }
}\,

int main() {
    // -------------------------- 20个pH校正案例（原始数据+偏移量+预期结果） --------------------------
    // 每个案例格式：{原始pH数组, 偏移量, 预期校正后数组}
    // 案例1-20覆盖不同场景：偏移量正负、pH值范围（酸性/中性/碱性）、边界值
    struct PHTestCase {
        float raw[5];       // 5个原始pH数据（模拟5次监测值）
        float offset;       // 校正偏移量
