        // 案例15：偏移量+0.7（强酸性→中性）
        {{4.8, 4.9, 4.7, 5.0, 4.6}, 0.7f, {5.5, 5.6, 5.4, 5.7, 5.3}, "Case15"},
        // 案例16：偏移量-0.8（强碱性→弱碱性）
        {{9.0, 8.9, 9.1, 8.8, 9.2}, -0.8f, {8.2, 8.1, 8.3, 8.0, 8.4}, "Case16"},
