        {{7.3, 7.4, 7.2, 7.5, 7.1}, -0.4f, {6.9, 7.0, 6.8, 7.1, 6.7}, "Case20"}
    };

    // 计算测试案例总数（数组总字节数 / 单个案例字节数）
    int caseCount = sizeof(testCases) / sizeof(testCases[0]);
    // 设置浮点数输出精度（保留1位小数，避免显示误差导致的校验错误）
    cout << fixed << setprecision(1);
    cout << "===================== 20个pH值校正案例结果 =====================
";

    // -------------------------- 遍历20个案例，执行校正并校验 --------------------------
    for (int i = 0; i < caseCount; i++) {
        PHTestCase& currentCase = testCases[i]; // 当前正在处理的案例
        int dataLen = sizeof(currentCase.raw) / sizeof(currentCase.raw[0]); // 每个案例的pH数据长度（固定为5）

        // 1. 复制原始数据（避免直接修改testCases中的原始数据，确保每个案例独立）
        float rawPH[5];
        for (int j = 0; j < dataLen; j++) {
            rawPH[j] = currentCase.raw[j];
        }

        // 2. 执行pH校正（调用calibratePH函数，指针传递数组）
        calibratePH(rawPH, dataLen, currentCase.offset);

        // 3. 输出当前案例的关键信息（优化换行，避免内容拥挤）
        cout << "【" << currentCase.caseID << "】 ";
        cout << "原始pH值：";
        for (int j = 0; j < dataLen; j++) cout << currentCase.raw[j] << " ";
        cout << "| 校正偏移量：" << currentCase.offset << " | ";
        cout << "实际校正后：";
        for (int j = 0; j < dataLen; j++) cout << rawPH[j] << " ";
        cout << "| 预期校正后：";
        for (int j = 0; j < dataLen; j++) cout << currentCase.expected[j] << " ";

        // 4. 校验：判断实际校正结果与预期是否一致（允许微小浮点数误差，用1e-6作为阈值）
        bool isCorrect = true;
        for (int j = 0; j < dataLen; j++) {
            // 浮点数比较：避免因精度问题（如6.3000001 vs 6.3）导致误判
            if (fabs(rawPH[j] - currentCase.expected[j]) > 1e-6) {
                isCorrect = false;
                break; // 只要有一个数据不一致，直接判定为校验失败
            }
        }

        // 5. 输出校验结果
        cout << "| 结果校验：" << (isCorrect ? "true" : "false") << "
";
    }

    // -------------------------- 整体校验总结 --------------------------
    int passCount = 0;
    for (int i = 0; i < caseCount; i++) {
        PHTestCase& currentCase = testCases[i];
        int dataLen = 5;
        float rawPH[5];
        for (int j = 0; j < dataLen; j++) rawPH[j] = currentCase.raw[j];

        calibratePH(rawPH, dataLen, currentCase.offset);
        bool isPass = true;
        for (int j = 0; j < dataLen; j++) {
            if (fabs(rawPH[j] - currentCase.expected[j]) > 1e-6) {
                isPass = false;
                break;
            }
        }
        if (isPass) passCount++;
    }

    cout << "===================== 整体校验总结 =====================
";
    cout << "总案例数：" << caseCount << " | 校验通过数：" << passCount << " | ";
    cout << "整体校验结果：" << (passCount == caseCount ? "true（全部通过）" : "false（存在失败案例）") << endl;

    return 0;
}

