struct LaneFlow {
    int laneID;    // 车道编号
    int carCount;  // 车道车流量（辆/小时）
};

struct RoadFlow {
    const char* roadID;  // 路段编号
    LaneFlow* lanes;     // 指向车道数据数组的指针
    int laneNum;         // 车道数量
};

// 补充核心函数声明
int calcTotalFlow(RoadFlow* road);

//结构体设计：嵌套指针的意义:LaneFlow（车道级数据）：存储单条车道的基础信息，是“最小数据单元”，无指针依赖，仅存储具体数值（laneID和carCount）。RoadFlow（路段级数据）：存储单个路段的汇总信息，核心是 LaneFlow* lanes 指针——通过指针指向该路段的所有车道数据数组，避免在结构体中直接存储数组（减少内存冗余，灵活适配不同车道数的路段）
//核心函数 calcTotalFlow:参数类型：接收 RoadFlow* 指针（而非值传递），避免拷贝整个 RoadFlow 结构体（尤其当车道数据量大时，提升效率）
//calcTotalFlow遍历逻辑：1. 定义 LaneFlow * lanePtr 指针，初始指向该路段的第一条车道（road->lanes）；2. 循环 road->laneNum 次（车道数决定循环次数），每次通过 lanePtr->carCount 访问当前车道的车流量并累加；3. 每次循环后 lanePtr++（指针偏移1个 LaneFlow 大小，指向 next 车道），本质是通过指针算术遍历数组

// 实现核心函数（删除多余逗号）
int calcTotalFlow(RoadFlow* road) {
    if (road == nullptr || road->lanes == nullptr || road->laneNum <= 0) {
        return 0; // 异常处理
    }
    int total = 0;
    LaneFlow* lanePtr = road->lanes;
    for (int i = 0; i < road->laneNum; i++) {
        total += lanePtr->carCount;
        lanePtr++;
    }
    return total;
}

