#include <iostream>
using namespace std;

//找传感器数据最大值：排除无效值，返回有效数据中的最大值
//函数 findMax 详解:该函数是传感器数据处理的核心，负责从指定数据中排除无效值（ - 999）并找到最大值，解决了原始代码中“初始值可能为无效值”的漏洞
//1.初始化最大值：先遍历数据找到第一个有效值（非 - 999），作为初始最大值maxVal；若数据全为无效值，直接返回 - 999，避免后续逻辑错误
//2.指针算术遍历：用endPtr = dataPtr + len定义遍历终止边界（指针指向数组末尾的下一个位置）；循环中通过dataPtr++移动指针，逐个检查数据：仅当数据有效且大于当前maxVal时，更新maxVal

int main() {
    // -------------------------- 20个传感器数据案例 --------------------------
    // 每个案例格式：{温度1, 温度2, 温度3, 温度4, 温度5, 温度6, 湿度1, 湿度2, 湿度3, 湿度4, 湿度5, 湿度6, 预期最高温度, 预期最高湿度}
    // 注：-999为无效值，每个案例包含6个温度数据、6个湿度数据，共12个传感器值
    struct SensorCase {
        float data[12];       // 传感器原始数据（前6温+后6湿）
        float expMaxTemp;     // 预期最高温度
        float expMaxHum;      // 预期最高湿度
        const char* caseName; // 案例名称（便于区分）
    };

    // 20个具体案例（覆盖有效值、无效值、边界值、全有效、含多个无效值等场景）
    SensorCase cases[] = {
        // 案例1：含1个无效温度、1个无效湿度
        {{25.3, -999, 26.1, 24.8, 27.2, 25.9, 65.2, 62.5, -999, 59.8, 68.3, 64.6}, 27.2, 68.3, "案例1：单无效温+单无效湿"}
    };

    // 计算案例总数
    int caseCount = sizeof(cases) / sizeof(cases[0]);
    cout << "=== 20个传感器数据最大值查找与校验 ===  ";

    // 遍历每个案例，执行最大值查找并校验
    for (int i = 0; i < caseCount; i++) {
        SensorCase current = cases[i];
        // 1. 输出当前案例名称
        cout << "【" << current.caseName << "】 ";

        // 2. 提取温度数据（前6个元素），调用findMax获取实际最高温度
        float* tempData = current.data; // 温度数据指针（指向数组首元素）
        float actualMaxTemp = findMax(tempData, 6, -999);
        // 提取湿度数据（后6个元素），指针偏移6位指向湿度起始位置
        float* humData = current.data + 6; // 湿度数据指针（指向第7个元素）
        float actualMaxHum = findMax(humData, 6, -999);

        // 3. 输出实际结果与预期结果
        cout << "  温度数据：";
        for (int j = 0; j < 6; j++) {
            if (current.data[j] == -999) cout << "无效 "; 
            else cout << current.data[j] << " "; 
        }
        cout << "   实际最高温度：" << actualMaxTemp << "℃ | 预期最高温度：" << current.expMaxTemp << "℃ ";

        cout << "  湿度数据：";
        for (int j = 6; j < 12; j++) {
            if (current.data[j] == -999) cout << "无效 "; 
            else cout << current.data[j] << " "; 
        }
        cout << "   实际最高湿度：" << actualMaxHum << "% | 预期最高湿度：" << current.expMaxHum << "% ";

        // 4. 校验实际结果与预期是否一致（考虑浮点数精度，允许±0.0001误差）
        const float eps = 1e-4; // 浮点数比较精度阈值
        bool tempCheck = (fabs(actualMaxTemp - current.expMaxTemp) < eps);
        bool humCheck = (fabs(actualMaxHum - current.expMaxHum) < eps);
        bool totalCheck = tempCheck && humCheck;

        // 5. 输出校验结果
        cout << "  温度校验：" << (tempCheck ? "true" : "false") << " | 湿度校验：" << (humCheck ? "true" : "false") << " ";
        cout << "  案例总校验：" << (totalCheck ? "true" : "false") << "  ";
    }

    // 统计所有案例的校验通过率
    int passCount = 0;
    for (int i = 0; i < caseCount; i++) {
        SensorCase current = cases[i];
        float actualMaxTemp = findMax(current.data, 6, -999);
