    float* expectedAvgs = new float[20] {
        1.4,   // 设备1：(1.2+1.5+1.3+1.4+1.6)/5 = 1.4
        };

    // 4. 遍历20台设备：计算实际均值、输出结果、校验与预期是否一致
    for (int i = 0; i < deviceNum; i++) {
        float actualAvg = calcDailyVib(vibData[i], dayCount); // 计算实际均值
