using namespace std;

//结构体定义BatteryCycle：存储电池单次循环的“循环次数（cycle）”和“剩余电量（soc，单位% ）”，用于描述电池循环过程中的状态
//结构体定义TestCase（主函数内定义）：存储测试案例的“初始电量（initial）”、“当前电量（current）”和“预期衰减率（expected）”，用于批量验证代码正确性
//核心函数 calcDecayRate功能：计算电池电量衰减率，公式为(初始电量 - 当前电量) / 初始电量 * 100（转为百分比，便于理解）;异常处理：若初始电量≤0，输出错误提示并返回 - 1.0f（标识计算失败），避免数学上的“除零错误”

int main() {
    // 定义20组测试案例：每组包含初始电量、当前电量、预期衰减率（保留2位小数）
    struct TestCase {
        float initial;
        float current;
        float expected;
    } testCases[20] = {
        {100.0f, 95.0f, 5.00f}
    };

    // 遍历20组案例，计算并验证结果
    for (int i = 0; i < 20; i++) {
        cout << "=== 测试案例 " << (i + 1) << " ===" << endl;
        float actual = calcDecayRate(testCases[i].initial, testCases[i].current);

        // 输出计算结果（保留2位小数，确保格式统一）
        if (actual == -1.0f) {
            cout << "计算结果：初始电量异常" << endl;
        }
        else {
            cout << "初始电量：" << testCases[i].initial << "%, 当前电量：" << testCases[i].current << "%" << endl;
            cout << "计算衰减率：" << fixed << setprecision(2) << actual << "%" << endl;
            cout << "预期衰减率：" << fixed << setprecision(2) << testCases[i].expected << "%" << endl;
        }

        // 判断实际结果与预期是否一致（考虑浮点数精度误差，允许±0.01的偏差）
        bool isMatch = false;
        if (testCases[i].expected == -1.0f) {
            isMatch = (actual == -1.0f); // 错误案例单独判断
        }
        else {
            // 浮点数比较：差值绝对值小于0.01即认为一致
            isMatch = (abs(actual - testCases[i].expected) < 0.01f);
        }

        cout << "结果匹配：" << (isMatch ? "true" : "false") << endl << endl;
    }

    return 0;
}

