bool verifyResult(const int* actual, size_t actualSize, const int* expected, size_t expectedSize) {
    if (actualSize != expectedSize) return false; // 长度不同直接不匹配
    for (size_t i = 0; i < actualSize; i++) {
        if (*(actual + i) != *(expected + i)) return false; // 元素不匹配
    }
    return true;
}

