#include <iostream>
#include <algorithm>
#include <cmath>
using namespace std;

class OutlierDetector {
private:
    double* data;       // 存储原始数据集（拷贝，避免修改外部数据）
    int size;           // 数据集元素个数
    bool* isOutlier;    // 标记数组：true=异常值，false=正常值（初始全为false）
    double Q1, Q3, IQR; // 四分位数（Q1=下四分位，Q3=上四分位）、四分位距
    double lowerBound;  // 异常值下界（Q1 - 1.5*IQR）
    double upperBound;  // 异常值上界（Q3 + 1.5*IQR）

public:
    // 构造函数：初始化数据集，拷贝外部数据到内部数组，初始化标记数组
    OutlierDetector(double* raw, int s) : size(s) {
        data = new double[size];
        for (int i = 0; i < size; i++) data[i] = raw[i]; // 深拷贝外部数据

        isOutlier = new bool[size](); // 动态数组初始化：所有元素默认false
    }

    // 辅助函数1：IQR异常值检测核心逻辑（计算四分位数、上下界，标记异常值）
    void detectByIQR() {
        // 1. 对数据集排序（排序是计算四分位数的前提）
        sort(data, data + size);

        // 2. 计算四分位数Q1和Q3（简化版：按索引取，适用于任意大小数据集）
        Q1 = data[size / 4];          // 下四分位：第25百分位（索引=size/4）
        Q3 = data[3 * size / 4];      // 上四分位：第75百分位（索引=3*size/4）
        IQR = Q3 - Q1;                // 四分位距：上四分位 - 下四分位

        // 3. 计算异常值判断边界
        lowerBound = Q1 - 1.5 * IQR;
        upperBound = Q3 + 1.5 * IQR;

        // 4. 标记异常值（小于下界或大于上界即为异常）
        for (int i = 0; i < size; i++) {
            isOutlier[i] = (data[i] < lowerBound) || (data[i] > upperBound);
        }
    }

    // 辅助函数2：获取异常值标记数组（用于外部验证）
    bool* getOutlierMarks() const {
        return isOutlier;
    }

    // 辅助函数3：获取计算出的上下界（用于外部验证）
    void getBounds(double& lower, double& upper) const {
        lower = lowerBound;
        upper = upperBound;
    }

    // 辅助函数4：获取排序后的数据集（用于外部验证四分位数计算）
    double* getSortedData() const {
        return data;
    }

    // 析构函数：释放动态分配的内存，避免内存泄漏
    ~OutlierDetector() {
        delete[] data;
        delete[] isOutlier;
    }
};

// 主函数：20个测试案例（覆盖不同数据场景，含结果判断与true/false输出）
int main() {
    // ------------------------------ 案例1：无异常值（均匀分布数据）
    cout << "=== 案例1：无异常值（均匀分布） ===" << endl;
    double data1[] = { 1,2,3,4,5,6,7,8 };
    int size1 = sizeof(data1) / sizeof(data1[0]);
    OutlierDetector od1(data1, size1);
    od1.detectByIQR();
    bool* marks1 = od1.getOutlierMarks();
    // 预期：所有值正常（false）
    bool res1 = true;
    for (int i = 0; i < size1; i++) {
        if (marks1[i]) res1 = false;
    }
    cout << "异常值标记（0=正常，1=异常）：";
    for (int i = 0; i < size1; i++) cout << marks1[i] << " ";
    cout << " 结果是否符合预期（无异常值）：" << (res1 ? "true" : "false") << "  ";

    return 0;
}

