#include <time.h>
#include <iostream>
#include <cassert>
using namespace std;

struct TimePoint 
{
    // 时间点结构体：存储时间戳和对应数值
    // 时间戳（秒级，自1970-01-01 00:00:00 UTC起）
    // 时间点对应的数值（如温度、湿度等）
    time_t timestamp;
    double value;
};

class TimeSeriesDataset 
{
private:
    TimePoint* data;  
    int len;          
public:
    TimeSeriesDataset(int l) : len(l) 
    {
        // 1. 构造函数：初始化len个时间点，时间间隔1小时（3600秒），初始值0.0
        // 边界处理：避免长度为负或0
        if (len <= 0)
        {
            len = 0;
            data = nullptr;
            return;
        }
        data = new TimePoint[len];
        time_t now = time(nullptr);
        for (int i = 0; i < len; ++i)
        {
            data[i].timestamp = now - i * 3600;
            data[i].value = 0.0;
        }
    }

    ~TimeSeriesDataset() 
    {
        // 2. 析构函数：释放动态数组内存，避免内存泄漏
        delete[] data;
        data = nullptr;
    }

    int getLength() const 
    {
        // 3. 获取数据长度（对外提供len的访问接口，隐藏私有成员）
        return len;
    }

    time_t getTimestamp(int index) const 
    {
        // 4. 获取指定索引的时间戳（索引0为最新时间，索引越大时间越旧）
        // 边界处理：索引越界时返回-1（无效时间戳）
        if (index < 0 || index >= len)
            return -1;
        return data[index].timestamp;
    }

    double getValue(int index) const 
    {
        // 5. 获取指定索引的数值
        // 边界处理：索引越界时返回NaN（无效数值）
        if (index < 0 || index >= len)
            return nan("");
        return data[index].value;
    }

    bool setValue(int index, double newVal) 
    {
        // 6. 修改指定索引的数值（支持更新数据）
        // 索引越界时修改失败，返回false
        if (index < 0 || index >= len)
            return false;
        data[index].value = newVal;
        return true;
    }

    bool isTimestampSorted() const 
    {
        // 7. 检查时间戳是否按“最新到最旧”排序（验证构造逻辑）
        for (int i = 0; i < len - 1; ++i)
        {
            if (data[i].timestamp <= data[i + 1].timestamp)
                return false;
        }
        return true;
    }
};

int main() 
{
    // 案例1：创建24小时数据，验证长度是否为24
    cout << "=== 案例1：验证24小时数据长度 ===" << endl;
    TimeSeriesDataset ts1(24);
    int actualLen1 = ts1.getLength();
    int expectedLen1 = 24;
    cout << "实际长度：" << actualLen1 << "，预期长度：" << expectedLen1 << endl;
    cout << (actualLen1 == expectedLen1 ? "true" : "false") << endl << endl;

    return 0;
}

