#include <cstdlib>
#include <ctime>   
#include <cstdio>  
#include <iostream> 
using namespace std; 

class RandomIntDataset 
{
private:
    int* data; 
    int size;   
public:
    RandomIntDataset(int s) : size(s) 
    {
        // 构造函数：生成指定大小的随机整数数组（范围0-99）
        // 若传入的大小小于等于0，默认创建大小为1的数组（避免非法内存分配）
        // 循环为每个数组元素赋值0-99的随机整数
        if (size <= 0)
            size = 1;
        data = new int[size];
        for (int i = 0; i < size; ++i)
            data[i] = rand() % 100;
    }

    void print() 
    {
        // 辅助函数1：打印数据集
        for (int i = 0; i < size; ++i)
        {
            cout << data[i];
            if (i != size - 1)
                cout << " ";
        }
        cout << endl;
    }

    int getSize() const 
    {
        // 辅助函数2：获取数据集大小（用于主函数判断）
        return size;
    }

    int getElement(int index) const 
    {
        // 辅助函数3：获取数组中指定索引的元素（用于主函数判断）
        // 若索引越界，返回-1（作为非法标识）
        if (index < 0 || index >= size)
            return -1;
        return data[index];
    }

    bool hasValue(int val) const 
    {
        // 辅助函数4：判断数据集中是否包含指定数值（用于主函数判断）
        for (int i = 0; i < size; ++i)
            if (data[i] == val)
                return true;
        return false;
    }

    int getMax() const 
    {
        // 辅助函数5：获取数据集中的最大值（用于主函数判断）
        if (size == 0)
            return -1; // 理论上不会触发，因构造函数保证size>=1
        int maxVal = data[0];
        for (int i = 1; i < size; ++i)
            if (data[i] > maxVal)
                maxVal = data[i];
        return maxVal;
    }

    ~RandomIntDataset() 
    {
        // 析构函数：释放动态分配的内存（避免内存泄漏）
        delete[] data;
    }
};

int main() 
{
    srand((unsigned int)time(NULL));

    // 案例1：创建大小为5的数据集，判断大小是否为5
    cout << "=== 案例1 ===" << endl;
    RandomIntDataset ds1(5);
    ds1.print();
    int actualSize1 = ds1.getSize();
    int expectSize1 = 5;
    cout << "实际大小：" << actualSize1 << "，预期大小：" << expectSize1;
    cout << "，判断结果：" << (actualSize1 == expectSize1 ? "true" : "false") << endl << endl;

    return 0;
}

