        sepalLen[0] = 5.1f;
        sepalLen[1] = 4.9f;
        sepalLen[2] = 4.7f;
    }

    IrisDataset(int count, const float* data) : sampleCount(count) 
    {
        // 重载构造函数1：支持自定义样本数量和萼片长度数据
        // 将外部传入的data数组值拷贝到类内部数组
        sepalLen = new float[sampleCount];
        for (int i = 0; i < sampleCount; ++i)
            sepalLen[i] = data[i];
    }

    IrisDataset(int count) : sampleCount(count) 
    {
        // 重载构造函数2：支持仅自定义样本数量（数组初始化为0）
        sepalLen = new float[sampleCount]();
    }

    float getMean() 
    {
        // 辅助函数1：获取萼片长度特征的均值
        if (sampleCount <= 0)
            return 0.0f;
        float sum = 0.0f;
        for (int i = 0; i < sampleCount; ++i)
            sum += sepalLen[i];
        return sum / sampleCount;
    }

    float getSepalLen(int index) 
    {
        // 辅助函数2：获取指定索引的萼片长度（用于单个样本值验证）
        // 索引合法性判断：避免越界访问
        if (index < 0 || index >= sampleCount)
            return -1.0f; // 越界标识
        return sepalLen[index];
    }

    int getSampleCount() 
    {
        // 辅助函数3：获取样本总数（用于验证样本数量）
        return sampleCount;
    }

    ~IrisDataset() 
    {
        // 析构函数：释放动态分配的数组内存，避免内存泄漏
        delete[] sepalLen;
    }
};

