#include <iostream>
#include <cmath>
using namespace std;

class TimeSeriesDataset
{
private:
    double* values;
    int len;
public:

    TimeSeriesDataset(double arr[], int l) : len(l)
    {
        values = new double[len];
        for (int i = 0; i < len; i++)
            values[i] = arr[i];
    }

    double* getFirstDiff()
    {
        if (len < 2)
            return nullptr;
        double* diff = new double[len - 1];
        for (int i = 0; i < len - 1; i++)
            diff[i] = values[i + 1] - values[i];
        return diff;
    }

    int getLength() const
    {
        return len;
    }

    ~TimeSeriesDataset()
    {
        delete[] values;
    }
};


bool compareDoubleArrays(double* arr1, double* arr2, int len)
{
    for (int i = 0; i < len; i++)
        if (fabs(arr1[i] - arr2[i]) >= 1e-6)
            return false;
    return true;
}

int main()
{
    double arr1[] = { 1, 2, 3, 4 };
    TimeSeriesDataset ts1(arr1, 4);
    double* diff1 = ts1.getFirstDiff();
    double expected1[] = { 1, 1, 1 };
    cout << "案例1 - 一阶差分结果：";
    for (int i = 0; i < ts1.getLength() - 1; i++) cout << diff1[i] << " ";
    cout << " | 与预期是否一致：" << boolalpha << compareDoubleArrays(diff1, expected1, 3) << endl;
    delete[] diff1;

    return 0;
}

