#include <iostream>
#include <cassert>
using namespace std;

class GrayImageDataset
{
private:
    unsigned char* pixels;
    int width, height;
public:
    GrayImageDataset(int w, int h) : width(w), height(h)
    {
        pixels = new unsigned char[width * height]();
    }

    void setPixel(int x, int y, unsigned char val)
    {
        if (x >= 0 && x < width && y >= 0 && y < height)
        {
            int index = y * width + x;
            pixels[index] = val;
        }
    }

    unsigned char getPixel(int x, int y)
    {
        if (x >= 0 && x < width && y >= 0 && y < height)
        {
            int index = y * width + x;
            return pixels[index];
        }
        return 0;
    }

    ~GrayImageDataset()
    {
        delete[] pixels;
    }
};

int main()
{
    // 示例1：2×2图像，给(0,0)赋值255（白色），验证值是否为255
    GrayImageDataset img1(2, 2);
    img1.setPixel(0, 0, 255);
    unsigned char res1 = img1.getPixel(0, 0);
    cout << "示例1：(0,0)像素值 = " << (int)res1;
    bool exp1 = (res1 == 255);
    cout << "，预期是否符合：" << boolalpha << exp1 << endl;

    return 0;
}

