        // 循环拷贝外部数组数据到内部 data 数组，实现数据独立存储（避免外部数组修改影响内部）
    }

    int markAnomaly(float min, float max) 
    {
        // 辅助函数：标记并统计超出 [min, max] 正常范围的异常值
        // 参数1：min - 数据正常范围的下限（如加速度正常范围下限1.0）
        // 参数2：max - 数据正常范围的上限（如加速度正常范围上限1.5）
        // 返回值：异常值的总数量（int类型）
        // 遍历所有传感器数据样本
        // 选择结构：判断当前数据是否超出正常范围（低于min或高于max即为异常）
    }

    ~SensorAnomalyDataset() 
    {
        // 析构函数：释放动态分配的内存，避免内存泄漏
    }
};

int main() 
{
    // 案例1：全正常数据（范围1.0-1.5），预期异常数0
