#include <iostream> 
#include <string>
using namespace std;

class DBDataSet 
{
protected:
    string connStr;
public:
    // 构造函数：初始化连接字符串
    DBDataSet(string conn) : connStr(conn) {}
    // 纯虚函数：执行查询，定义接口规范，子类必须实现
    virtual bool executeQuery(string sql) = 0;
    // 辅助函数：验证连接字符串是否非空
    bool checkConn() { return !connStr.empty(); }
};

class MySqlDataSet : public DBDataSet 
{
public:
    // 构造函数：调用父类构造初始化连接字符串
    MySqlDataSet(string conn) : DBDataSet(conn) {}

    bool executeQuery(string sql) override 
    {
        // 重写父类纯虚函数:实现MySQL的查询执行逻辑
        if (!checkConn()) {
            cout << "连接字符串为空，查询失败！" << endl;
            return false;
        }
        cout << "MySQL执行查询:" << sql << endl;
        cout << "连接信息：" << connStr << endl;
        // 模拟查询成功(实际场景需调用MySQL API实现真实查询)
        return true;
    }
};

int main() 
{
    // 案例1:正常连接字符串 + 简单查询
    MySqlDataSet db1("server=localhost;user=root;pwd=123456;db=test");
    bool res1 = db1.executeQuery("SELECT * FROM users");
    cout << "案例1 - 实际结果：" << boolalpha << res1 << ",预期结果:true → " << (res1 == true ? "true" : "false") << endl << endl;

    return 0;
}

