#include <iostream>
#include <vector>
#include <string>
using namespace std;

class TimeSeriesDataset 
{
protected:
    vector<double> values; 
public:
    // 构造函数：初始化数据容器
    TimeSeriesDataset(vector<double> v) : values(v) {}
    // 纯虚函数：定义按时间格式输出的接口（子类必须实现）
    virtual void printByTimeFormat(string format) = 0;
    // 成员函数：获取数据长度（数据点数量）
    int getDataLength() { return values.size(); }
    // 虚析构函数：确保子类对象销毁时调用正确的析构逻辑
    virtual ~TimeSeriesDataset() {}
};

class UnixTimeDataset : public TimeSeriesDataset 
{
public:
    // 构造函数：调用父类构造初始化数据
    UnixTimeDataset(vector<double> v) : TimeSeriesDataset(v) {}

    void printByTimeFormat(string format) override 
    {
        // 重写父类纯虚函数：实现Unix时间格式的输出逻辑
        if (values.empty()) {
            cout << "数据容器为空，无数据可输出！" << endl;
            return;
        }
        cout << "Unix时间格式（" << format << "）输出数据点：" << endl;
        for (int i = 0; i < values.size(); ++i) {
            cout << "第" << (i + 1) << "个数据点：" << values[i] << "（Unix时间戳）" << endl;
        }
    }
};

int main() 
{
    // 案例1：空数据容器
    vector<double> data1;
    UnixTimeDataset ds1(data1);
    cout << "案例1 - 输出结果：";
    ds1.printByTimeFormat("timestamp");
    bool case1 = (ds1.getDataLength() == 0);
    cout << "案例1 - 结果是否符合预期（预期0个数据点）：" << (case1 ? "true" : "false") << endl << endl;

    return 0;
}

