#include <iostream>
using namespace std;

class TextDataset 
{
protected:
    string content; 
public:
    TextDataset(string cnt) : content(cnt) {}
    // 纯虚函数：按指定编码保存，定义抽象接口
    virtual bool saveAsEncoding(string encoding) = 0;
    // 辅助函数：计算文本字符数（基于string的size()）
    int getCharCount() { return content.size(); }
    // 虚析构函数：确保子类对象析构时正确调用子类析构逻辑
    virtual ~TextDataset() {}
};

class Utf8TextDataset : public TextDataset 
{
public:
    // 构造函数：调用父类构造函数初始化文本内容
    Utf8TextDataset(string cnt) : TextDataset(cnt) {}

