#include <vector>
#include <string>
#include <iostream>
using namespace std;

class SensorDataset 
{
protected:
    vector<float> readings; 
    string deviceId;        
public:
    // 构造函数：初始化传感器的读数和设备ID
    SensorDataset(vector<float> r, string id) : readings(r), deviceId(id) {}

    // 纯虚函数：校准数据（子类必须实现具体校准逻辑，体现多态）
    virtual void calibrate() = 0;

    // 成员函数：获取设备ID（对外提供设备标识的访问接口）
    string getDeviceId() { return deviceId; }

    // 成员函数：获取读数数量（用于验证数据点数量，辅助判断逻辑）
    int getReadingCount() { return readings.size(); }
};

class TemperatureSensorDataset : public SensorDataset 
{
public:
    // 构造函数：调用父类构造函数初始化温度传感器数据
    TemperatureSensorDataset(vector<float> r, string id) : SensorDataset(r, id) {}

    void calibrate() override 
    {
        // 重写校准函数：实现温度传感器的校准逻辑（打印校准信息）
        cout << "校准温度传感器 [" << deviceId << "]，共" << readings.size() << "个数据点" << endl;
        cout << "温度校准完成：偏移量修正+0.1℃" << endl; // 模拟校准逻辑
    }
};

int main() 
{
    // 示例1：设备ID=TEMP-001，5个温度读数，预期ID=TEMP-001、数据点=5
    TemperatureSensorDataset temp1({ 22.5, 23.1, 22.8, 23.0, 22.7 }, "TEMP-001");
    temp1.calibrate();
    bool check1 = (temp1.getDeviceId() == "TEMP-001" && temp1.getReadingCount() == 5);
    cout << "Example 1: Expected (ID=TEMP-001, 5 points) -> Result: " << boolalpha << check1 << endl << endl;

