#include <iostream>  
#include <string>
using namespace std;

class DistributedDataset 
{
protected:
    int nodeCount; 
public:
    DistributedDataset(int nodes) : nodeCount(nodes) {}
    // 纯虚函数：定义同步节点数据的接口，子类必须实现
    virtual bool syncNodes() = 0;
    // 辅助函数：验证节点数是否合法（至少1个）
    bool isValidNodeCount() { return nodeCount >= 1; }
    // 新增获取节点数的接口，用于主函数验证预期
    int getNodeCount() { return nodeCount; }
};

class HdfsDataset : public DistributedDataset 
{
public:
    HdfsDataset(int nodes) : DistributedDataset(nodes) {}

    bool syncNodes() override 
    {
        // 重写纯虚函数，实现HDFS数据集的节点同步逻辑
        if (isValidNodeCount())
        {
            cout << "HDFS节点同步成功，当前节点数：" << nodeCount << "  "; 
            return true;
        }
        else
        {
            cout << "HDFS节点数不合法（需至少1个），同步失败  "; 
            return false;
        }
    }
};

int main() 
{
    // 测试案例1：节点数=1（合法，预期同步成功）
    HdfsDataset h1(1);
    bool res1 = h1.syncNodes();
    bool exp1 = true;
    cout << "Case 1 - Actual Result: " << boolalpha << res1 << ", Expected Result: " << exp1
        << ", Match: " << (res1 == exp1 ? "true" : "false") << "  ";

    return 0;
}

