#include <vector>
#include <string>
#include <iostream>
using namespace std;

class SparseDataset 
{
protected:
    vector<pair<int, double>> sparseData; 
public:
    SparseDataset(vector<pair<int, double>> data) : sparseData(data) {}
    // 虚函数：压缩数据（纯虚函数，强制子类实现）
    virtual void compress(string method) = 0;
    // 辅助函数：计算非零元素数（稀疏数据的核心特征）
    int getNonZeroCount() { return sparseData.size(); }
    // 新增：获取稀疏数据（用于测试验证）
    vector<pair<int, double>> getSparseData() { return sparseData; }
};

class Lz4SparseDataset : public SparseDataset 
{
public:
    Lz4SparseDataset(vector<pair<int, double>> data) : SparseDataset(data) {}

    void compress(string method) override 
    {
        // 重写压缩函数：实现LZ4算法的压缩逻辑（此处为模拟输出）
        cout << "使用LZ4算法以[" << method << "]模式压缩，非零元素数：" << getNonZeroCount() << endl;
    }
};

int main() 
{
    // 测试案例1：空稀疏数据（无任何非零元素）
    vector<pair<int, double>> data1;
    Lz4SparseDataset ds1(data1);
    int exp1 = 0; // 预期非零元素数
    int res1 = ds1.getNonZeroCount();
    cout << "案例1：空数据，非零元素数=" << res1;
    cout << "，结果是否符合预期：" << (res1 == exp1 ? "true" : "false") << endl;
    ds1.compress("Fast");

    return 0;
}

