#include <string>
#include <vector>
using namespace std;

class LabeledDataset 
{
protected:
    vector<string> labels; 
public:
    // 构造函数：初始化标注列表
    LabeledDataset(vector<string> lbls) : labels(lbls) {}
    // 纯虚函数：定义标注验证接口，子类必须实现
    virtual bool validateLabels() = 0;
    // 成员函数：获取标注数量
    int getLabelCount() { return labels.size(); }
    // 虚析构函数：确保子类对象析构时调用正确的析构函数（虽此处无动态内存，但为规范添加）
    virtual ~LabeledDataset() {}
};

class ClassificationDataset : public LabeledDataset 
{
public:
    // 构造函数：调用父类构造函数初始化标注列表
    ClassificationDataset(vector<string> lbls) : LabeledDataset(lbls) {}

    bool validateLabels() override 
    {
        // 重写纯虚函数：实现分类数据集的标注验证逻辑
        // 验证逻辑：标注列表非空即视为有效
        return !labels.empty();
    }
};

