#include <string>
#include <iostream>  
using namespace std;

class StreamDataset 
{
protected:
    string streamUrl; 
public:
    StreamDataset(string url) : streamUrl(url) {}
    // 虚函数：接收流数据（纯虚函数，使基类成为抽象类）
    virtual void receiveStream(bool realTime) = 0;
    // 辅助函数：检查流地址是否有效（非空即为有效）
    bool isStreamUrlValid() { return !streamUrl.empty(); }
    // 辅助函数：获取流地址（用于主函数判断结果）
    string getStreamUrl() { return streamUrl; }
};

class KafkaStreamDataset : public StreamDataset 
{
public:
    KafkaStreamDataset(string url) : StreamDataset(url) {}

    void receiveStream(bool realTime) override 
    {
        // 重写基类虚函数：实现Kafka流数据接收逻辑
        if (isStreamUrlValid())
        {
            cout << "从Kafka流[" << streamUrl << "]接收数据，模式：" << (realTime ? "实时" : "批量") << endl;
        }
        else
        {
            cout << "Kafka流地址无效，无法接收数据" << endl;
        }
    }
};

int main() 
{
    // 案例1：有效URL + 实时接收
    KafkaStreamDataset k1("kafka://server1:9092/topic1");
    cout << "=== Case 1 ===" << endl;
    k1.receiveStream(true);
    bool case1_ok = (k1.getStreamUrl() == "kafka://server1:9092/topic1" && k1.isStreamUrlValid());
    cout << "Case 1 Result Check: " << (case1_ok ? "true" : "false") << endl << endl;

    return 0;
}

