#include <iostream>
#include <vector>
#include <cmath> 
using namespace std;

class DataPreprocessor 
{
protected:
    vector<vector<double>> data;  
    const double EPS = 1e-6;      
public:
    // 构造函数1：初始化数据（核心构造）
    DataPreprocessor(vector<vector<double>> d) : data(d) {}

    // 构造函数2：默认构造（空数据）
    DataPreprocessor() : data() {}

    // 纯虚函数：数据预处理（子类必须重写，实现具体逻辑）
    virtual void preprocess() = 0;

    void printData() const 
    {
        // 辅助函数1：输出处理后的数据
        for (size_t i = 0; i < data.size(); ++i)
        {
            for (size_t j = 0; j < data[i].size(); ++j)
            {
                cout << data[i][j];
                if (j != data[i].size() - 1) cout << " ";
            }
            cout << endl;
        }
        // 避免末尾多余空格
    }

    vector<vector<double>> getData() const 
    {
        // 辅助函数2：获取处理后的数据（用于外部结果验证）
        return data;
    }

    bool isEqual(const vector<vector<double>>& expected) const 
    {
        // 辅助函数3：验证当前数据与预期数据是否一致（处理浮点数精度）
        // 1. 检查样本数量是否一致
        if (data.size() != expected.size()) return false;
        // 2. 检查每个样本的特征数量是否一致
        for (size_t i = 0; i < data.size(); ++i)
        {
            if (data[i].size() != expected[i].size()) return false;
        }
        // 3. 逐元素检查数值是否一致（容忍微小误差）
        for (size_t i = 0; i < data.size(); ++i)
        {
            for (size_t j = 0; j < data[i].size(); ++j)
            {
                if (fabs(data[i][j] - expected[i][j]) > EPS) return false;
            }
        }
        return true;
    }

    bool isEmpty() const 
    {
        // 辅助函数4：检查数据是否为空
        return data.empty();
    }
};

class Normalizer : public DataPreprocessor 
{
public:
    // 构造函数：复用基类构造
    Normalizer(vector<vector<double>> d) : DataPreprocessor(d) {}

    void preprocess() override 
    {
        // 重写虚函数：实现归一化逻辑（按特征列计算min/max）
        if (data.empty() || data[0].empty()) return;
        size_t featureNum = data[0].size();
        // 逐特征列计算最小值和最大值
        for (size_t j = 0; j < featureNum; ++j)
        {
            // 第一步：找该列的min和max
            double minVal = data[0][j];
            double maxVal = data[0][j];
            for (size_t i = 1; i < data.size(); ++i)
            {
                if (data[i][j] < minVal) minVal = data[i][j];
                if (data[i][j] > maxVal) maxVal = data[i][j];
            }
            // 避免除以零（若该列所有值相同，归一化后全为0）
            if (fabs(maxVal - minVal) < EPS)
            {
                for (size_t i = 0; i < data.size(); ++i)
                {
                    data[i][j] = 0.0;
                }
            }
            else
            {
                // 第二步：归一化（x' = (x - min)/(max - min)）
                for (size_t i = 0; i < data.size(); ++i)
                {
                    data[i][j] = (data[i][j] - minVal) / (maxVal - minVal);
                }
            }
        }
    }
};

// 子类2：数据标准化（Z-Score Standardization，均值=0，方差=1）
class Standardizer : public DataPreprocessor 
{
public:
    // 构造函数：复用基类构造
    Standardizer(vector<vector<double>> d) : DataPreprocessor(d) {}

    void preprocess() override 
    {
        // 重写虚函数：实现标准化逻辑（按特征列计算均值和标准差）
        if (data.empty() || data[0].empty()) return;
        size_t featureNum = data[0].size();
        // 逐特征列计算均值和标准差
        for (size_t j = 0; j < featureNum; ++j)
        {
            // 第一步：计算该列的均值（mean）
            double mean = 0.0;
            for (size_t i = 0; i < data.size(); ++i)
            {
                mean += data[i][j];
            }
            mean /= data.size();
            // 第二步：计算该列的标准差（std）
            double std = 0.0;
            for (size_t i = 0; i < data.size(); ++i)
            {
                std += pow(data[i][j] - mean, 2);
            }
            std = sqrt(std / data.size());
            // 避免除以零（若该列所有值相同，标准化后全为0）
            if (fabs(std) < EPS)
            {
                for (size_t i = 0; i < data.size(); ++i)
                {
                    data[i][j] = 0.0;
                }
            }
            else
            {
                // 第三步：标准化（x' = (x - mean)/std）
                for (size_t i = 0; i < data.size(); ++i)
                {
                    data[i][j] = (data[i][j] - mean) / std;
                }
            }
        }
    }
};

int main() {
    // 案例1：2x2整数数据（Normalizer，正常场景）
    cout << "=== Case 1: 2x2 Integer Data (Normalizer) ===" << endl;
    vector<vector<double>> d1 = { {1, 2}, {3, 4} };
    vector<vector<double>> exp1 = { {0.0, 0.0}, {1.0, 1.0} };  // 归一化预期：特征1(min=1,max=3)，特征2(min=2,max=4)
    DataPreprocessor* p1 = new Normalizer(d1);
    p1->preprocess();
    cout << "Processed Data:" << endl;
    p1->printData();
    bool case1_ok = p1->isEqual(exp1);
    cout << "Case 1 Check (Match Expected?): " << (case1_ok ? "true" : "false") << " " << endl;
    delete p1;

    return 0;
}

