#include <vector>
#include <iostream>
#include <cmath> 
using namespace std;

class ScalableDataset 
{
private:
    vector<vector<double>> features; 
    const double EPS = 1e-6;       
public:
    // 构造函数：初始化特征
    ScalableDataset(vector<vector<double>> feat) : features(feat) {}

    void printFeatures() const 
    {
        // 辅助函数1：输出特征矩阵
        for (size_t i = 0; i < features.size(); ++i)
        {
            for (size_t j = 0; j < features[i].size(); ++j)
            {
                cout << features[i][j];
                if (j != features[i].size() - 1) cout << " ";
            }
            cout << endl;
        }
    }

    vector<vector<double>> getFeatures() const 
    {
        // 辅助函数2：获取特征矩阵（用于主函数验证结果）
        return features;
    }

    bool isEqual(const vector<vector<double>>& expected) const 
    {
        // 辅助函数3：验证当前数据集是否与预期特征矩阵一致（处理浮点数精度）
        // 先判断行数是否一致
        if (features.size() != expected.size()) return false;
        // 再逐行、逐元素判断（允许微小误差）
        for (size_t i = 0; i < features.size(); ++i)
        {
            if (features[i].size() != expected[i].size()) return false;
            for (size_t j = 0; j < features[i].size(); ++j)
            {
                if (fabs(features[i][j] - expected[i][j]) > EPS) return false;
            }
        }
        return true;
    }

    ScalableDataset operator*(double scale) const 
    {
        // 重载*：特征矩阵所有元素乘以系数（缩放操作）
        vector<vector<double>> scaled = features;
        for (size_t i = 0; i < scaled.size(); ++i)
        {
            for (size_t j = 0; j < scaled[i].size(); ++j)
            {
                scaled[i][j] *= scale;
            }
        }
        return ScalableDataset(scaled);
    }
};

int main() 
{
    // 案例1：正系数（0.5）+ 2x2矩阵
    cout << "=== Case 1 ===" << endl;
    ScalableDataset d1({ {1.0, 2.0}, {3.0, 4.0} });
    ScalableDataset scaled1 = d1 * 0.5;
    vector<vector<double>> exp1 = { {0.5, 1.0}, {1.5, 2.0} };
    cout << "Scaled Features:" << endl;
    scaled1.printFeatures();
    bool case1_ok = scaled1.isEqual(exp1);
    cout << "Case 1 Match Expected? " << (case1_ok ? "true" : "false") << endl << endl;

    return 0;
}

