#include <iostream>
#include <vector>
#include <string>
#include <sstream>  
using namespace std;

class TextTokenizer 
{
protected:
    vector<string> texts; 
public:
    // 构造函数1：初始化原始文本
    TextTokenizer(vector<string> t) : texts(t) {}

    // 构造函数2：默认构造（空文本）
    TextTokenizer() : texts() {}

    // 纯虚函数：分词核心逻辑（子类必须重写，实现不同分词规则）
    virtual vector<vector<string>> tokenize() const = 0;

    void printTokens(const vector<vector<string>>& tokens) const 
    {
        // 辅助函数1：输出分词结果详情
        for (size_t i = 0; i < tokens.size(); ++i)
        {
            cout << "Text " << i + 1 << " tokens: "; 
            for (size_t j = 0; j < tokens[i].size(); ++j)
            {
                cout << "[" << tokens[i][j] << "]";
                if (j != tokens[i].size() - 1) cout << " ";
            }
            cout << endl;
        }
    }

    int getTotalTokenCount(const vector<vector<string>>& tokens) const 
    {
        // 辅助函数2：统计总分词数量
        int count = 0;
        for (const auto& tokenList : tokens)
        {
            count += tokenList.size();
        }
        return count;
    }

    bool isTokenEqual(const vector<vector<string>>& tokens, const vector<vector<string>>& expected) const 
    {
        // 辅助函数3：验证分词结果是否与预期一致
        // 1. 先检查文本数量是否匹配
        if (tokens.size() != expected.size()) return false;
        // 2. 再检查每个文本的分词列表是否匹配
        for (size_t i = 0; i < tokens.size(); ++i)
        {
            if (tokens[i].size() != expected[i].size()) return false;
            for (size_t j = 0; j < tokens[i].size(); ++j)
            {
                if (tokens[i][j] != expected[i][j]) return false;
            }
        }
        return true;
    }
};

class SpaceTokenizer : public TextTokenizer 
{
public:
    // 构造函数：调用基类构造初始化文本
    SpaceTokenizer(vector<string> t) : TextTokenizer(t) {}

    vector<vector<string>> tokenize() const override 
    {
        // 重写虚函数：实现空格分词逻辑（实际切割字符串，非模拟）
        vector<vector<string>> result;
        for (const string& text : texts)
        {
            vector<string> tokens;
            istringstream iss(text);
            string token;
            while (iss >> token)
            {
                tokens.push_back(token);
            }
            result.push_back(tokens);
        }
        return result;
    }
};

class CharTokenizer : public TextTokenizer 
{
public:
    // 构造函数：调用基类构造初始化文本
    CharTokenizer(vector<string> t) : TextTokenizer(t) {}

    vector<vector<string>> tokenize() const override 
    {
        // 重写虚函数：实现单字分词逻辑（遍历每个字符）
        vector<vector<string>> result;
        for (const string& text : texts)
        {
            vector<string> tokens;
            for (char c : text)
            {
                // 遍历字符串每个字符，转为string存入列表
                tokens.push_back(string(1, c));
            }
            result.push_back(tokens);
        }
        return result;
    }
};

// 子类3：下划线分词（按下划线切割，补充场景：如变量名分词）
class UnderscoreTokenizer : public TextTokenizer 
{
public:
    UnderscoreTokenizer(vector<string> t) : TextTokenizer(t) {}

    vector<vector<string>> tokenize() const override 
    {
        vector<vector<string>> result;
        for (const string& text : texts)
        {
            vector<string> tokens;
            size_t start = 0;
            size_t pos = text.find('_');
            while (pos != string::npos)
            {
                if (pos > start)
                {
                    tokens.push_back(text.substr(start, pos - start));
                }
                start = pos + 1;
                pos = text.find('_', start);
            }
            // 添加最后一个未分割的token
            if (start < text.size())
            {
                tokens.push_back(text.substr(start));
            }
            result.push_back(tokens);
        }
        return result;
    }
};

int main() 
{
    // 案例1：SpaceTokenizer-英文短句（2个文本，正常空格分割）
    cout << "=== Case 1: SpaceTokenizer (English Short Texts) ===" << endl;
    vector<string> text1 = { "Hello world", "Data processing is fun" };
    vector<vector<string>> exp1 = { {"Hello", "world"}, {"Data", "processing", "is", "fun"} };
    TextTokenizer* tokenizer1 = new SpaceTokenizer(text1);
    vector<vector<string>> res1 = tokenizer1->tokenize();
    tokenizer1->printTokens(res1);
    bool case1_ok = tokenizer1->isTokenEqual(res1, exp1);
    cout << "Total Tokens: " << tokenizer1->getTotalTokenCount(res1) << endl;
    cout << "Case 1 Check (Match Expected?): " << (case1_ok ? "true" : "false") << " " << endl;
    delete tokenizer1;

    return 0;
}

