#include <iostream>
#include <string>
#include <vector>
#include <sstream>
#include <cmath>
using namespace std;

// 基类：通用数据存储（定义数据存储的统一接口，支持多存储介质扩展）
// 核心功能：管理数据唯一标识，提供存储接口，支持结果验证
class DataStorage 
{
protected:
    string dataId;         
    const double EPS = 1e-6;

    // 辅助函数（protected）：模拟存储操作结果记录（用于验证）
    virtual string getStoreResultRecord() const = 0;

public:
    DataStorage(string id) : dataId(id) 
    {
        // 构造函数1：初始化数据ID（带合法性校验，避免空ID）
        if (id.empty())
        {
            throw invalid_argument("Data ID cannot be empty");
        }
    }

    // 构造函数2：默认构造（空ID，用于特殊场景）
    DataStorage() : dataId("") {}

    // 纯虚函数：数据存储核心逻辑（子类必须重写，实现具体存储介质的存储）
    virtual void store() const = 0;

    string getDataId() const 
    {
        // 辅助函数1：获取数据ID（用于外部验证和日志记录）
        return dataId;
    }

    bool isStoreResultValid(const string& expectedRecord) const 
    {
        // 辅助函数2：验证存储结果是否与预期一致（对比存储记录）
        // 忽略空格差异，仅对比核心内容
        string actual = getStoreResultRecord();
        string exp = expectedRecord;
        // 移除所有空格
        actual.erase(remove_if(actual.begin(), actual.end(), ::isspace), actual.end());
        exp.erase(remove_if(exp.begin(), exp.end(), ::isspace), exp.end());
        return actual == exp;
    }

    void printStoreLog(const string& mediumType, const string& target) const 
    {
        // 辅助函数3：输出存储操作日志（统一格式，便于查看）
        cout << "Stored data [ID=" << dataId << "] to " << mediumType << " target: " << target << endl;
    }
};

// 派生类1：文件存储（继承通用存储，实现本地文件存储）
class FileStorage : public DataStorage 
{
private:
    string filePath;       
    mutable string storeLog;

    string getStoreResultRecord() const override 
    {
        // 重写：获取文件存储结果记录（用于验证）
        return "FileStore:ID=" + dataId + ",Path=" + filePath;
    }

public:
    FileStorage(string id, string path) : DataStorage(id), filePath(path) 
    {
        // 构造函数：初始化数据ID+文件路径（调用基类构造，确保ID合法）
        if (path.empty())
        {
            throw invalid_argument("File path cannot be empty");
        }
    }

    void store() const override 
    {
         // 重写：文件存储逻辑（模拟文件写入操作，记录日志）
        storeLog = "File written to " + filePath + " (ID: " + dataId + ")";
        printStoreLog("File", filePath);
    }

    string getFilePath() const 
    {
        // 辅助函数：获取文件路径（用于外部验证）
        return filePath;
    }
};

// 派生类2：数据库存储（继承通用存储，实现关系型数据库存储）
class DBStorage : public DataStorage 
{
private:
    string dbConn;         
    string tableName;       
    mutable string storeLog;

    string getStoreResultRecord() const override 
    {
        // 重写：获取数据库存储结果记录（用于验证）
        return "DBStore:ID=" + dataId + ",Conn=" + dbConn + ",Table=" + tableName;
    }

public:
    DBStorage(string id, string conn, string table)
        : DataStorage(id), dbConn(conn), tableName(table) 
    {
        // 构造函数：初始化数据ID+连接串+表名（调用基类构造，确保ID合法)
        if (conn.empty() || table.empty())
        {
            throw invalid_argument("DB connection or table name cannot be empty");
        }
    }

    void store() const override 
    {
        // 重写：数据库存储逻辑（模拟SQL插入操作，记录日志）
        storeLog = "SQL inserted into " + tableName + " via " + dbConn + " (ID: " + dataId + ")";
        printStoreLog("Database", dbConn + "::" + tableName);
    }

    string getDBInfo() const 
    {
        // 辅助函数：获取数据库连接信息（用于外部验证）
        return dbConn + "::" + tableName;
    }
};

// 派生类3：云存储（新增派生类，实现云服务存储，扩展存储介质）
class CloudStorage : public DataStorage 
{
private:
    string bucketName;     
    string cloudRegion;   
    mutable string storeLog;

    string getStoreResultRecord() const override 
    {
        // 重写：获取云存储结果记录（用于验证）
        return "CloudStore:ID=" + dataId + ",Bucket=" + bucketName + ",Region=" + cloudRegion;
    }

public:
    CloudStorage(string id, string bucket, string region)
        : DataStorage(id), bucketName(bucket), cloudRegion(region) 
    {
        // 构造函数：初始化数据ID+桶名+区域（调用基类构造）
        if (bucket.empty() || region.empty())
        {
            throw invalid_argument("Cloud bucket or region cannot be empty");
        }
    }

    void store() const override 
    {
        // 重写：云存储逻辑（模拟云上传操作，记录日志）
        storeLog = "Object uploaded to " + bucketName + " (" + cloudRegion + ") (ID: " + dataId + ")";
        printStoreLog("Cloud", cloudRegion + "/" + bucketName);
    }

    string getCloudInfo() const 
    {
        // 辅助函数：获取云存储信息（用于外部验证）
        return cloudRegion + "/" + bucketName;
    }
};

