#include <iostream>
#include <string>
#include <vector>
#include <utility> 
using namespace std;

class Feature 
{
protected:
    string featName;
    int featDim;     
public:
    // 构造函数：初始化特征名称+维度
    Feature(string name, int dim) : featName(name), featDim(dim) {}

    // 析构函数：为实现多态析构，确保派生类对象正确释放
    virtual ~Feature() = default;

    string getFeatInfo() const 
    {
        // 辅助函数：获取特征基本信息
        return "Feature(name=" + featName + ", dim=" + to_string(featDim) + ")";
    }

    // 虚函数：特征标准化（供子类重写）
    virtual void standardize() const = 0;

    // 新增：获取标准化预期结果（用于后续判断）
    virtual string getExpectedStdResult() const = 0;
};

// 派生类1：数值特征（继承通用特征，新增数值范围属性）
class NumericFeature : public Feature 
{
private:
    pair<double, double> valueRange; 
    mutable string actualStdResult; // 存储实际标准化结果
public:
    // 构造函数：初始化特征名+维度+数值范围
    NumericFeature(string name, int dim, double min, double max)
        : Feature(name, dim), valueRange({min, max}) {}

    void standardize() const override 
    {
        // 重写标准化：数值特征标准化（缩放到[0,1]）
        actualStdResult = "NumericFeature '" + featName + "' standardized to [0,1] (range: [" + 
                        to_string(valueRange.first) + ", " + to_string(valueRange.second) + "])";
        cout << actualStdResult;
    }

    string getExpectedStdResult() const override 
    {
        // 重写：获取数值特征标准化预期结果
        return "NumericFeature '" + featName + "' standardized to [0,1] (range: [" + 
               to_string(valueRange.first) + ", " + to_string(valueRange.second) + "])";
    }

    string getActualStdResult() const 
    {
        // 新增：获取实际标准化输出字符串（用于对比）
        return actualStdResult;
    }
};

// 派生类2：文本特征（继承通用特征，新增词汇表大小属性）
class TextFeature : public Feature 
{
private:
    int vocabSize; 
    mutable string actualStdResult; // 存储实际标准化结果
public:
    // 构造函数：初始化特征名+维度+词汇表大小
    TextFeature(string name, int dim, int vocab)
        : Feature(name, dim), vocabSize(vocab) {}

    void standardize() const override 
    {
        // 重写标准化：文本特征标准化（TF-IDF归一化）
        actualStdResult = "TextFeature '" + featName + "' standardized with TF-IDF (vocab size: " + 
                        to_string(vocabSize) + ")";
        cout << actualStdResult;
    }

    string getExpectedStdResult() const override 
    {
        // 重写：获取文本特征标准化预期结果
        return "TextFeature '" + featName + "' standardized with TF-IDF (vocab size: " + 
               to_string(vocabSize) + ")";
    }

    string getActualStdResult() const 
    {
        // 新增：获取实际标准化输出字符串（用于对比）
        return actualStdResult;
    }
};

int main() 
{
    // 1. 数值特征：年龄（0-120岁，1维）
    Feature* f1 = new NumericFeature("age", 1, 0.0, 120.0);
    cout << "Case 1: ";
    f1->standardize();
    bool res1 = dynamic_cast<NumericFeature*>(f1)->getActualStdResult() == f1->getExpectedStdResult();
    cout << " → Match: " << boolalpha << res1 << endl;
    delete f1;

    return 0;
}

