#include <iostream>
#include <vector>
#include <string>
#include <cctype> 
using namespace std;

class DataValidator 
 {
protected:
 string dataType;
public:
 // 构造函数：初始化数据类型 
 DataValidator (string type) : dataType (type) {}

 // 虚函数：执行校验（供子类重写）
 virtual bool validate (const string& data) const = 0;

 void printResult (const string& data) const 
 {
 // 辅助函数：输出校验结果 
 bool valid = validate (data);
 cout << "Validate [" << dataType << "] data: '" << data << "' →" << (valid ? "Yes" : "No");
 }

 // 析构函数：确保子类对象正确释放 
 virtual ~DataValidator () = default;
};

// 派生类 1：格式校验（继承通用校验，校验字符串格式如邮箱、手机号）
class FormatValidator : public DataValidator 
 {
private:
 string formatRule; 
public:
 // 构造函数：初始化数据类型 + 格式规则 
 FormatValidator (string type, string rule)
 : DataValidator (type), formatRule (rule) {}

 bool validate (const string& data) const override 
 {
 // 重写校验：支持邮箱、手机号（简化逻辑）
 if (formatRule == "email")
 {
 // 邮箱简化校验：包含 @和.，且 @不在开头 / 结尾，. 在 @之后 
 size_t atPos = data.find ('@');
 size_t dotPos = data.find ('.', atPos + 1);
 return !data.empty () && atPos != string::npos && atPos != 0 && atPos != data.size ()-1 && dotPos != string::npos && dotPos != data.size ()-1;
 }
 else if (formatRule == "phone")
 {
 // 手机号简化校验：11 位数字，以 1 开头 
 if (data.size () != 11) return false;
 if (data [0] != '1') return false;
 for (char c : data)
 {
 if (!isdigit (c)) return false;
 }
 return true;
 }
 return false;
 }
};

// 派生类 2：范围校验（继承通用校验，校验数值范围）
class RangeValidator : public DataValidator 
 {
private:
 int minVal, maxVal; 
public:
 // 构造函数：初始化数据类型 + 数值范围 
 RangeValidator (string type, int min, int max)
 : DataValidator (type), minVal (min), maxVal (max) {}

 bool validate (const string& data) const override 
 {
 // 重写校验：验证数值是否在范围内（处理非数字输入）
 // 先判断是否为纯数字（支持负号）
 if (data.empty ()) return false;
 size_t i = 0;
 if (data [0] == '-')
 {
 if (data.size () == 1) return false; // 单独负号无效 
 i = 1;
 }
 for (; i < data.size (); ++i)
 {
 if (!isdigit (data [i])) return false;
 }
 // 转换为整数并判断范围 
 int num = stoi (data);
 return num >= minVal && num <= maxVal;
 }
};

