#include <iostream>
#include <string>
using namespace std;

class ImageData 
{
protected:
    int width, height; 
    string imgPath;    
public:
    // 构造函数：初始化宽、高、路径
    ImageData(int w, int h, string path)
        : width(w), height(h), imgPath(path) {}

    string getSize() const 
    {
        // 辅助函数：获取图像尺寸
        return to_string(width) + "x" + to_string(height);
    }

    // 虚函数：图像加载（供子类重写）
    virtual void loadImage() const = 0;

    string getPath() const 
    {
        // 新增：获取图像路径（用于测试判断）
        return imgPath;
    }

    virtual int getGrayLevel() const 
    {
        // 新增：获取灰度级（灰度图专用，彩色图返回-1，用于测试判断）
        return -1;
    }

    virtual int getChannels() const 
    {
        // 新增：获取通道数（彩色图专用，灰度图返回-1，用于测试判断）
        return -1;
    }

    // 析构函数：避免内存泄漏
    virtual ~ImageData() = default;
};

// 派生类1：灰度图像（继承通用图像，新增灰度级属性）
class GrayImage : public ImageData 
{
private:
    int grayLevel; 
public:
    // 构造函数：初始化宽、高、路径、灰度级
    GrayImage(int w, int h, string path, int level)
        : ImageData(w, h, path), grayLevel(level) {}

    void loadImage() const override 
    {
        // 重写加载：灰度图像加载
        cout << "Loading grayscale image from " << imgPath << " (" << getSize() << "), " << grayLevel << " levels" << endl;
    }

    int getGrayLevel() const override 
    {
        // 重写：返回灰度级
        return grayLevel;
    }
};

// 派生类2：彩色图像（继承通用图像，新增通道数属性）
class ColorImage : public ImageData 
{
private:
    int channels; 
public:
    // 构造函数：初始化宽、高、路径、通道数
    ColorImage(int w, int h, string path, int ch)
        : ImageData(w, h, path), channels(ch) {}

    void loadImage() const override 
    {
        // 重写加载：彩色图像加载
        cout << "Loading color image from " << imgPath << " (" << getSize() << "), " << channels << " channels" << endl;
    }

    int getChannels() const override 
    {
        // 重写：返回通道数
        return channels;
    }
};

int main() 
{
    // 案例1：640x480灰度图（256级）
    ImageData* img1 = new GrayImage(640, 480, "./gray1.jpg", 256);
    img1->loadImage();
    bool res1 = (img1->getSize() == "640x480" && img1->getGrayLevel() == 256);
    cout << "Case1: " << (res1 ? "true" : "false") << endl << endl;
    delete img1;

    return 0;
}

